// frontend/src/FlowCanvas.jsx
import React, { useRef } from "react";
import ReactFlow, { Background, Controls, MiniMap } from "reactflow";
import "reactflow/dist/style.css";
import { InputNode } from "./nodes/inputNode";
import { LLMNode } from "./nodes/llmNode";
import { TextNode } from "./nodes/textNode";
import { OutputNode } from "./nodes/outputNode";
import { DeleteNode } from "./nodes/deleteNode";
import { submitPipeline } from "./submit";

// Define nodeTypes locally instead of importing from registryNode
const nodeTypes = {
  inputNode: InputNode,
  llmNode: LLMNode,
  textNode: TextNode,
  outputNode: OutputNode,
  deleteNode: DeleteNode,
};

export default function FlowCanvas({
  nodes,
  edges,
  onNodesChange,
  onEdgesChange,
  onConnect,
  setNodes,
}) {
  const reactFlowWrapper = useRef(null);

  const handleSubmit = () => {
    submitPipeline(nodes, edges);
  };

  const onDragOver = (event) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = "move";
  };

  const onDrop = (event) => {
    event.preventDefault();
    const reactFlowBounds = reactFlowWrapper.current.getBoundingClientRect();
    const data = JSON.parse(event.dataTransfer.getData("application/reactflow"));

    if (!data.nodeType) {
      console.error("No nodeType in drop data");
      return;
    }

    const position = {
      x: event.clientX - reactFlowBounds.left,
      y: event.clientY - reactFlowBounds.top,
    };

    // Generate unique ID
    const nodeId = `${data.nodeType}-${Date.now()}`;
    
    // Create base node data
    let nodeData = data.data || { label: data.nodeType };
    
    // Ensure each node type has proper initial data
    switch(data.nodeType) {
      case 'inputNode':
        nodeData = {
          inputName: `input_${Date.now().toString().slice(-4)}`,
          inputType: 'Text',
          label: 'Input',
          ...nodeData
        };
        break;
      case 'llmNode':
        nodeData = {
          label: 'LLM',
          ...nodeData
        };
        break;
      case 'textNode':
        nodeData = {
          text: '{{input}}',
          label: 'Text',
          ...nodeData
        };
        break;
      case 'outputNode':
        nodeData = {
          outputName: `output_${Date.now().toString().slice(-4)}`,
          outputType: 'Text',
          label: 'Output',
          ...nodeData
        };
        break;
      case 'deleteNode':
        nodeData = {
          candidates: [],
          onDelete: () => console.log("Delete initialized"),
          canDeleteTool: false,
          label: 'Delete Node',
          ...nodeData
        };
        break;
    }

    const newNode = {
      id: nodeId,
      type: data.nodeType,
      position,
      data: nodeData,
      className: data.className || "",
    };

    console.log("Creating new node:", newNode);
    setNodes((nds) => [...nds, newNode]);
  };

  return (
    <div 
      ref={reactFlowWrapper}
      style={{ width: "100%", height: "100%", position: "relative" }}
    >
      <ReactFlow
        nodes={nodes}
        edges={edges}
        nodeTypes={nodeTypes}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onDrop={onDrop}
        onDragOver={onDragOver}
        fitView
      >
        <Background />
        <Controls />
        <MiniMap />
      </ReactFlow>

      <button
        onClick={handleSubmit}
        style={{
          position: "absolute",
          top: 20,
          right: 20,
          zIndex: 10,
          padding: "8px 16px",
          backgroundColor: "#4f46e5",
          color: "#fff",
          border: "none",
          borderRadius: "6px",
          cursor: "pointer",
          fontWeight: "600",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
        }}
      >
        Submit Pipeline
      </button>
    </div>
  );
}
